#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int reversePairs(vector<int>& nums) {
        return mergeSort(nums);
    }

private:
    int mergeSort(vector<int>& nums) {
        if (nums.size() <= 1) {
            return 0;
        }
        int mid = nums.size() / 2;
        vector<int> left(nums.begin(), nums.begin() + mid);
        vector<int> right(nums.begin() + mid, nums.end());
        int leftCount = mergeSort(left);
        int rightCount = mergeSort(right);
        int mergeCount = merge(nums, left, right);
        return leftCount + rightCount + mergeCount;
    }

    int merge(vector<int>& nums, vector<int>& left, vector<int>& right) {
        int i = 0, j = 0, k = 0, count = 0;
        while (i < left.size() && j < right.size()) {
            if (left[i] <= 2 * right[j]) {
                nums[k++] = left[i++];
            } else {
                nums[k++] = right[j++];
                count += left.size() - i;
            }
        }
        while (i < left.size()) {
            nums[k++] = left[i++];
        }
        while (j < right.size()) {
            nums[k++] = right[j++];
        }
        return count;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> nums(n);
    for (int i = 0; i < n; i++) cin >> nums[i];
    Solution sol;
    int ans = sol.reversePairs(nums);
    cout << ans << '\n';
    return 0;
}
